}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Blog – WordPress.org Italia\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"https://it.wordpress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"width\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:67:\"Il progetto pilota della Contributor Dashboard è online: e adesso?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://it.wordpress.org/news/2026/03/il-progetto-pilota-della-contributor-dashboard-e-online-e-adesso/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:111:\"https://it.wordpress.org/news/2026/03/il-progetto-pilota-della-contributor-dashboard-e-online-e-adesso/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 06 Mar 2026 20:03:30 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"Community\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://it.wordpress.org/?p=4257\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:415:\"Partendo dal thread iniziale del progetto, il progetto pilota della Contributor Dashboard è ora online, segnando un passo importante verso una visione più chiara di come le persone iniziano a contribuire, partecipano e crescono all’interno del progetto WordPress. Questo post illustra le funzionalità proposte per la prossima fase del progetto pilota della Contributor Dashboard. Condividiamo queste [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Francesco Di Candia\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8551:\"\n<p class=\"wp-block-paragraph\">Partendo dal <a href=\"https://make.wordpress.org/project/2025/12/20/project-thread-contributor-dashboard-pilot-project/\" target=\"_blank\" rel=\"noreferrer noopener\">thread iniziale del progetto</a>, il progetto pilota della Contributor Dashboard è ora online, segnando un passo importante verso una visione più chiara di come le persone iniziano a contribuire, partecipano e crescono all’interno del progetto WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Questo post illustra le funzionalità proposte per la prossima fase del progetto pilota della Contributor Dashboard. Condividiamo queste idee in anticipo per raccogliere feedback dalla community prima dell’inizio dell’implementazione.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Stato attuale</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Il progetto pilota della dashboard è finalmente pronto:</strong> <a href=\"https://wpcontributordashboard.org/\" target=\"_blank\" rel=\"noreferrer noopener\">https://wpcontributordashboard.org/</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">Le funzionalità di <strong>base</strong> presenti sono:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Sistema di import CSV per i dati inerenti le attività di contributo</li>\n\n\n\n<li>Architettura dei dati a tre livelli (Eventi <span aria-hidden=\"true\" class=\"wp-exclude-emoji\">→</span> Profili <span aria-hidden=\"true\" class=\"wp-exclude-emoji\">→</span> Dashboard)<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</li>\n\n\n\n<li>Framework della “Contributor Ladder” (ladder di progresso dei contributor)</li>\n\n\n\n<li>Monitoraggio dello stato di attività (attivo/attenzione/inattivo)<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Lo sviluppo avviene nel <a href=\"https://github.com/WordPress/wporg-contributor-dashboard\" target=\"_blank\" rel=\"noreferrer noopener\">repository pubblico GitHub</a> e puoi vedere <a href=\"https://cleanshot.com/share/hkpxHJjc\">qui</a> la demo video della dashboard.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Contributor di diversi team Make stanno sviluppando il progetto pilota della Contributor Dashboard. I collaboratori del progetto includono <a href=\'https://profiles.wordpress.org/felipevelzani/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>felipevelzani</a>, <a href=\'https://profiles.wordpress.org/unintended8/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>unintended8</a>, <a href=\'https://profiles.wordpress.org/francescodicandia/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>francescodicandia</a>, <a href=\'https://profiles.wordpress.org/dd32/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>dd32</a> e <a href=\'https://profiles.wordpress.org/kel-dc/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>kel-dc</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Funzionalità proposte</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Per la prossima fase proponiamo due funzionalità e, su entrambe, sono benvenuti feedback.</p>\n\n\n\n<h3 class=\"wp-block-heading\">1. Personas gestite dai team</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Ogni team Make può creare le <strong>proprie contributor</strong> personas, con ladder e requisiti personalizzati che riflettano il modo in cui quel team effettivamente lavora.<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</p>\n\n\n\n<p class=\"wp-block-paragraph\">I diversi team contribuiscono in modi differenti, quindi un solo ladder non può andare bene per tutti. I team reps possono definire e gestire queste personas, e i contributor possono apparire in più ladder in base alla loro attività nei vari team.<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esempi d’uso:</strong><a rel=\"noreferrer noopener\" target=\"_blank\" href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\"></a>​</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>I Polyglots possono creare personas specifiche per ciascuna lingua per chi contribuisce alla traduzione.<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</li>\n\n\n\n<li>Il team Community può creare personas per gli organizzatori di WordCamp o Meetup.<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</li>\n\n\n\n<li>Il team Support può separare chi contribuisce nei forum da chi cerca aiuto.<br><a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a></li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">2. Coinvolgimento automatico</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Riconoscere <strong>automaticamente</strong> quando i contributor raggiungono tappe importanti.<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</p>\n\n\n\n<p class=\"wp-block-paragraph\">Un riconoscimento tempestivo migliora la retention e rafforza la partecipazione. Quando qualcuno effettua il suo primo contributo, raggiunge un nuovo gradino del ladder o rimane costantemente attivo, il sistema può inviare messaggi, props o regalare gadget (stickers, ecc.) dal <a href=\"https://mercantile.wordpress.org/\" target=\"_blank\" rel=\"noreferrer noopener\">Mercantile</a>.<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</p>\n\n\n\n<p class=\"wp-block-paragraph\">Il riconoscimento sarà integrato nel sistema e non sarà manuale.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Richiesta di feedback</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Ci piacerebbe conoscere la tua opinione su queste proposte. Se dovessimo partire da una sola delle due, quale porterebbe più valore al progetto? Ci sono altre cose non considerate che pensi dovrebbero essere implementate e/o che potrebbero portare molto valore?<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</p>\n\n\n\n<p class=\"wp-block-paragraph\">L’obiettivo generale è creare un sistema incentrato sul miglioramento complessivo dell’esperienza dei contributor.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Condividi qualsiasi feedback entro il <strong>17 marzo 2026</strong>, prevediamo di avviare la nuova fase entro questa data.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Come partecipare</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Se ti interessa contribuire a queste funzionalità:<a rel=\"noreferrer noopener\" target=\"_blank\" href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\"></a>​</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Commenta questo post con feedback o domande<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</li>\n\n\n\n<li>Unisciti alla discussione nel canale Slack <code>#contributor-dashboard</code><a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</li>\n\n\n\n<li>Dai un’occhiata al <a href=\"https://make.wordpress.org/handbook/contributor-dashboard/\" target=\"_blank\" rel=\"noreferrer noopener\">Contributor Dashboard Handbook</a> e al <a href=\"https://github.com/WordPress/wporg-contributor-dashboard\" target=\"_blank\" rel=\"noreferrer noopener\">repository GitHub</a> per i dettagli tecnici e contribuisci con il working group<a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\" target=\"_blank\" rel=\"noreferrer noopener\"></a>​</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Questo post è la traduzione del post originale in inglese che puoi trovare <a href=\"https://make.wordpress.org/project/2026/03/04/the-contributor-dashboard-pilot-is-live-whats-next/\">qui</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:108:\"https://it.wordpress.org/news/2026/03/il-progetto-pilota-della-contributor-dashboard-e-online-e-adesso/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"4257\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"Tutti i meetup di ottobre 2025\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"https://it.wordpress.org/news/2025/10/tutti-i-meetup-di-ottobre-2025/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://it.wordpress.org/news/2025/10/tutti-i-meetup-di-ottobre-2025/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 05 Oct 2025 15:29:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Uncategorized\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://it.wordpress.org/?p=4217\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:329:\"In tutta Italia ci sono meetup WordPress! I meetup sono incontri gratuiti e aperti a tutti, in cui le community locali si incontrano per condividere conoscenze, conoscersi e fare rete. Se non sai cos’è un meetup leggi la nostra Guida ai meetup. Non sai quali meetup sono attivi in Italia? Cerca il meetup più vicino [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Margherita Pelonara\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:1907:\"<p class=\"wp-block-paragraph\">In tutta Italia ci sono meetup WordPress!</p><p>I meetup sono <strong>incontri gratuiti e aperti a tutti,</strong> in cui le community locali si incontrano per condividere conoscenze, conoscersi e fare rete.</p><p class=\"wp-block-paragraph\">Se non sai cos’è un meetup <a href=\"https://it.wordpress.org/meetup/guida-ai-meetup-di-wordpress/\">leggi la nostra Guida ai meetup.</a></p><p class=\"wp-block-paragraph\">Non sai quali meetup sono attivi in Italia? <a href=\"https://it.wordpress.org/meetup/\">Cerca il meetup più vicino a te.</a></p><p class=\"wp-block-paragraph\"><strong>Nei prossimi giorni, <em>in ordine cronologico</em>, si incontrano le community di:</strong></p><h2 class=\"wp-block-heading\">Milano</h2><p class=\"wp-block-paragraph\">mer 8 ott, ore 17:00, &#8220;Progettare per l&#8217;inclusione culturale&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-milano/events/308967169/\">Milano: iscriviti per partecipare</a></p><h2 class=\"wp-block-heading\">Torino</h2><p class=\"wp-block-paragraph\">gio 16 ott, ore 16:30, &#8220;WordPress TO #104 A.M.A. (Ask Me Anything). Hai una domanda su WP o WooCommerce?&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-torino/events/311219606/\">Torino: iscriviti per partecipare</a></p><h2 class=\"wp-block-heading\">Roma</h2><p class=\"wp-block-paragraph\">ven 17 ott, ore 16:00, &#8220;Editor Aumentato: Come Automazione e AI possono moltiplicare la tua produttività&#8221; &#8211; <a href=\"https://www.meetup.com/romawordpress/events/308259638/\">Roma: iscriviti per partecipare</a></p><div style=\"height:var(--wp--preset--spacing--50)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><p class=\"has-text-align-center has-dark-blueberry-color has-blueberry-3-background-color has-text-color has-background has-link-color has-extra-large-font-size wp-block-paragraph\">… articolo in aggiornamento…</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://it.wordpress.org/news/2025/10/tutti-i-meetup-di-ottobre-2025/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"4217\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:100:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Tutti i meetup di giugno 2025\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"https://it.wordpress.org/news/2025/06/tutti-i-meetup-di-giugno-2025/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://it.wordpress.org/news/2025/06/tutti-i-meetup-di-giugno-2025/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 19 Jun 2025 09:10:02 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:10:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:6:\"ancona\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:4:\"bari\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:7:\"catania\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:5:\"lecce\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:5;a:5:{s:4:\"data\";s:6:\"milano\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:6;a:5:{s:4:\"data\";s:4:\"pisa\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:7;a:5:{s:4:\"data\";s:4:\"roma\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:8;a:5:{s:4:\"data\";s:6:\"torino\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:9;a:5:{s:4:\"data\";s:8:\"zagarolo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://it.wordpress.org/?p=4171\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:329:\"In tutta Italia ci sono meetup WordPress! I meetup sono incontri gratuiti e aperti a tutti, in cui le community locali si incontrano per condividere conoscenze, conoscersi e fare rete. Se non sai cos’è un meetup leggi la nostra Guida ai meetup. Non sai quali meetup sono attivi in Italia? Cerca il meetup più vicino [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Margherita Pelonara\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3915:\"\n<p class=\"wp-block-paragraph\">In tutta Italia ci sono meetup WordPress!</p>\n\n\n\n<p class=\"wp-block-paragraph\">I meetup sono <strong>incontri gratuiti e aperti a tutti,</strong> in cui le community locali si incontrano per condividere conoscenze, conoscersi e fare rete.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Se non sai cos’è un meetup <a href=\"https://it.wordpress.org/meetup/guida-ai-meetup-di-wordpress/\">leggi la nostra Guida ai meetup.</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">Non sai quali meetup sono attivi in Italia? <a href=\"https://it.wordpress.org/meetup/\">Cerca il meetup più vicino a te.</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nei prossimi giorni, <em>in ordine cronologico</em>, si incontrano le community di:</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Ancona</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mer 18 giu, ore 18:30, &#8220;Accessibilità web: un diritto e un dovere&#8221; &#8211; <a href=\"https://www.meetup.com/meetup-wordpress-ancona/events/308226204\">Ancona: iscriviti per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Milano</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mer 18 giu, ore 19:00, &#8220;Report da WordCamp Europe 2025 e Community Day&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-milano/events/308083151\">Milano: iscriviti per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Roma</h2>\n\n\n\n<p class=\"wp-block-paragraph\">ven 20 giu, ore 18:00, &#8220;Accessibilità web: un diritto e un dovere&#8221; &#8211; <a href=\"https://www.meetup.com/romawordpress/events/308259625\">Roma: iscriviti per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Lecce</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mar 24 giu, ore 18:00, &#8220;Accessibility Act 2025: le nuove regole per l&#8217;accessibilità digitale&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-lecce/events/308003575\">Lecce: iscriviti per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Zagarolo</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mer 25 giu, ore 18:00, &#8220;Cookie e Tempi di Cottura: come il GDPR ha cambiato la ricetta del web&#8221; &#8211; <a href=\"https://www.meetup.com/zagarolo-wordpress-meetup/events/308435314\">Zagarolo: iscriviti per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Pisa</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mer 25 giu, ore 18:00, &#8220;Dentro il WordCamp Europe 2025: novità, trend e community&#8221; &#8211; <a href=\"https://www.meetup.com/pisa-wordpress-meetup/events/308392278\">Pisa: iscriviti per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Catania</h2>\n\n\n\n<p class=\"wp-block-paragraph\">gio 26 giu, ore 19:00, &#8220;WordPress Meetup Catania Giugno 2025: AI Vs Sviluppatore&#8221; &#8211; <a href=\"https://www.meetup.com/meetup-wordpress-catania/events/308537700\">Catania: iscriviti per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Torino</h2>\n\n\n\n<p class=\"wp-block-paragraph\">gio 26 giu, ore 19:00, &#8220;Racconti da Basilea intorno a una pizza&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-torino/events/308459706\">Torino: iscriviti per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Terni</h2>\n\n\n\n<p class=\"wp-block-paragraph\">gio 26 giu, ore 19:30, &#8220;Pizza!&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-terni/events/308558415\">Terni: iscriviti per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Bari</h2>\n\n\n\n<p class=\"wp-block-paragraph\">ven 27 giu, ore 18:30, &#8220;Call for Speakers per il WordPress Meetup Bari&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-bari/events/308083833\">Bari: iscriviti per partecipare</a></p>\n\n\n\n<div style=\"height:var(--wp--preset--spacing--50)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-dark-blueberry-color has-blueberry-3-background-color has-text-color has-background has-link-color has-extra-large-font-size wp-block-paragraph\">… articolo in aggiornamento…</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://it.wordpress.org/news/2025/06/tutti-i-meetup-di-giugno-2025/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"4171\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"Trasforma le tue idee in talk coinvolgenti – #WPDiversity Workshop\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:102:\"https://it.wordpress.org/news/2025/04/trasforma-le-tue-idee-in-talk-coinvolgenti-wpdiversity-workshop/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:110:\"https://it.wordpress.org/news/2025/04/trasforma-le-tue-idee-in-talk-coinvolgenti-wpdiversity-workshop/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 24 Apr 2025 12:00:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Uncategorized\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://it.wordpress.org/?p=4144\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:363:\"Hai mai sognato di parlare a un evento di WordPress, ma una vocina interiore ti ha sussurrato &#8220;non sei abbastanza&#8221;, &#8220;non hai niente da dire&#8221;, &#8220;le tue esperienze e conoscenze non hanno valore&#8221;? Vorresti salire sul palco ma non hai idea di quale argomento parlare? Pensi e ripensi da molto tempo di volerti candidare ma [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Margherita Pelonara\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6345:\"\n<p class=\"has-large-font-size wp-block-paragraph\">Hai mai sognato di parlare a un evento di WordPress, ma una vocina interiore ti ha sussurrato &#8220;non sei abbastanza&#8221;, &#8220;non hai niente da dire&#8221;, &#8220;le tue esperienze e conoscenze non hanno valore&#8221;? Vorresti salire sul palco ma non hai idea di quale argomento parlare? Pensi e ripensi da molto tempo di volerti candidare ma continui ad avere paura e a rimandare?</p>\n\n\n\n<h2 class=\"wp-block-heading is-style-default\">Il #WPDiversity Workshop è quel che ti serve</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Ti capiamo. L&#8217;idea di parlare a un evento WordPress può accendere una scintilla di entusiasmo, ma subito dopo l&#8217;ombra del dubbio si allunga: &#8220;<em>Cosa potrei mai raccontare di interessante?</em>&#8220;. Forse hai accarezzato l&#8217;idea di candidarti mille volte, sentendo però una barriera invisibile, fatta di paure silenziose e convinzioni limitanti.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Se ti riconosci in queste sensazioni, sappi che non sei l&#8217;unica persona che le sperimenta! </p>\n\n\n\n<p class=\"wp-block-paragraph\">Questo invito è per <strong>te</strong>, che appartieni a un <strong>gruppo sottorappresentato</strong> (donne, comunità LGBTQIA+, persone razzializzate, persone con disabilità&#8230;) e nutri una grande passione per WordPress che freme sotto la superficie, in attesa di emergere.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Immagina di superare quel muro invisibile, di trasformare le tue insicurezze in pura energia creativa. Puoi farlo!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Il gruppo di lavoro #DEIB</strong> ha organizzato un ciclo di <strong>due laboratori online</strong> e gratuiti,  un vero e proprio <strong>viaggio trasformativo</strong> con l&#8217;obiettivo di aumentare la diversità fra le persone che salgono sul palco agli eventi WordPress:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Scaveremo nel profondo</strong> per capire le tue paure e smantellarle.</li>\n\n\n\n<li><strong>Esploreremo insieme attraverso attività pratiche</strong> quali argomenti legati a WordPress risuonano dentro di te e come possono diventare ottimi talk.</li>\n\n\n\n<li><strong>Nutriremo la tua sicurezza interiore</strong>, passo dopo passo, esercitandoci in uno spazio accogliente e protetto.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Al termine di queste due sessioni pratiche, avrai una nuova consapevolezza di te, ottenendo anche:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Un tesoro di <strong>idee brillanti</strong> per i tuoi futuri talk.</li>\n\n\n\n<li>Una <strong>bozza di scaletta</strong> che darà forma al tuo messaggio.</li>\n\n\n\n<li>Un <strong>titolo magnetico</strong> e un <strong>pitch/proposta irresistibile</strong> per farti notare.</li>\n\n\n\n<li>Una <strong>biografia che racconta la tua storia</strong> in modo autentico.</li>\n\n\n\n<li><strong>Consigli pratici</strong> per creare slide che incantano e includono.</li>\n\n\n\n<li>Il <strong>desiderio di candidarti</strong> per il prossimo meetup o WordCamp.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Non importa se il palco ti sembra un pianeta alieno! Questi laboratori sono pensati per <strong>tutti i livelli</strong>, anche per chi non ha mai osato immaginarsi sotto i riflettori.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Dove, Quando, Come:</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Unisciti a <a href=\'https://profiles.wordpress.org/simo70/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>simo70</a>, <a href=\'https://profiles.wordpress.org/margheweb/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>margheweb</a> e <a href=\'https://profiles.wordpress.org/eleonoraanzini/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>eleonoraanzini</a></strong> in questa avventura che cambierà la tua prospettiva e ti darà l&#8217;entusiasmo per candidarti come speaker al prossimo evento di WordPress!</p>\n\n\n\n<h4 class=\"wp-block-heading\">Martedì 06 maggio, ore 18:30, tramite Google Meet:</h4>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Scopriremo insieme perché la tua voce è fondamentale per la community WordPress.</li>\n\n\n\n<li>Affronteremo i fantasmi del passato che ti hanno bloccato.</li>\n\n\n\n<li>Impareremo a trasformare le tue paure in superpoteri.</li>\n\n\n\n<li>Demoliremo i falsi miti che avvolgono il public speaking.</li>\n\n\n\n<li>Faremo brainstorming per trovare l&#8217;argomento che ti farà brillare.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://meet.google.com/pip-tzek-skw\">PARTECIPA ALLA CALL DEL 06 MAG 25</a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-dots\" />\n\n\n\n<h4 class=\"wp-block-heading\">Martedì 20 maggio, ore 18:30, tramite Google Meet:</h4>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Creeremo proposte di talk che catturano l&#8217;attenzione fin dal titolo.</li>\n\n\n\n<li>Scriveremo biografie che raccontano la tua unicità.</li>\n\n\n\n<li>Progetteremo slide che comunicano con potenza e inclusività.</li>\n\n\n\n<li>Ci prepareremo ad affrontare le domande del pubblico con sicurezza.</li>\n\n\n\n<li>Sprigioneremo la tua sicurezza interiore.</li>\n\n\n\n<li>E, soprattutto, ti daremo la spinta per <strong>candidarti e far sentire la tua voce!</strong></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"http://meet.google.com/pip-tzek-skw\">PARTECIPA ALLA CALL DEL 20 MAG 25</a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-dots\" />\n\n\n\n<p class=\"wp-block-paragraph\">Preparati a <strong>esercizi pratici ed emozionanti</strong>, pensati per farti uscire dalla tua zona di comfort e svelare il potenziale oratore che è in te. Se lo desideri, riceverai un <strong>feedback immediato</strong> per affinare le tue capacità.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Questi non saranno semplici webinar: saranno <strong>due laboratori di trasformazione profonda</strong>. Mettiti in gioco, partecipa attivamente, e scoprirai una nuova consapevolezza di te, delle tue competenze e delle infinite possibilità che ti aspettano.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>È ora di smettere di sognare e iniziare a brillare. Iscriviti al #WPDiversity Workshop e preparati a conquistare il palco (e i cuori!) della community WordPress!</strong> <img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2764.png\" alt=\"❤\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:107:\"https://it.wordpress.org/news/2025/04/trasforma-le-tue-idee-in-talk-coinvolgenti-wpdiversity-workshop/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"4144\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"Protagoniste nel Tech\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://it.wordpress.org/news/2025/03/protagoniste-nel-tech/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 03 Mar 2025 16:20:19 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Uncategorized\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://it.wordpress.org/?p=4097\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:415:\"Esperienze e visioni di donne che ispirano Martedì 11 marzo ore 16-20, Casa delle Donne Terni Un&#8217;iniziativa promossa da @eleonoraanzini e @margheweb nell&#8217;ambito del Festival “(r)Esistenze Femministe”, festival organizzato dalla Casa delle Donne di Terni, alla sua seconda edizione. Un pomeriggio speciale dedicato alle donne che lavorano nel settore digitale e tecnologico, con una tavola [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Margherita Pelonara\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7677:\"\n<figure class=\"wp-block-image aligncenter size-full\"><img fetchpriority=\"high\" decoding=\"async\" width=\"600\" height=\"200\" src=\"https://it.wordpress.org/files/2025/03/WP-Evento-Protagoniste-nel-Tech.png\" alt=\"\" class=\"wp-image-4130\" srcset=\"https://it.wordpress.org/files/2025/03/WP-Evento-Protagoniste-nel-Tech.png 600w, https://it.wordpress.org/files/2025/03/WP-Evento-Protagoniste-nel-Tech-300x100.png 300w\" sizes=\"(max-width: 600px) 100vw, 600px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading has-text-align-center\">Esperienze e visioni di donne che ispirano</h2>\n\n\n\n<p class=\"has-text-align-center wp-block-paragraph\">Martedì 11 marzo ore 16-20, Casa delle Donne Terni</p>\n\n\n\n<p class=\"wp-block-paragraph\">Un&#8217;iniziativa promossa da <a href=\'https://profiles.wordpress.org/eleonoraanzini/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>eleonoraanzini</a> e <a href=\'https://profiles.wordpress.org/margheweb/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>margheweb</a> nell&#8217;ambito del Festival <strong><a href=\"https://www.lacasadelledonne.it/festival2025\">“(r)Esistenze Femministe”</a></strong>, festival organizzato dalla Casa delle Donne di Terni, alla sua seconda edizione.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-dots\" />\n\n\n\n<p class=\"wp-block-paragraph\">Un pomeriggio speciale dedicato alle donne che lavorano nel settore digitale e tecnologico, con una tavola rotonda, sessioni di dibattito, e a seguire un&#8217;edizione speciale del WordPress Meetup Terni, in cui le donne della Community di WordPress Italia condivideranno esperienze e conoscenze. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Un&#8217;occasione unica per ascoltare interventi stimolanti, creare connessioni e discutere delle sfide e delle opportunità per le donne nel mondo del tech.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-dots\" />\n\n\n\n<h2 class=\"wp-block-heading\">Celebriamo la Giornata internazionale dei diritti delle donne con questo evento trasversale che coinvolge le donne della Community di WordPress e la Casa delle Donne di Terni.</h2>\n\n\n\n<p class=\"wp-container-content-9cfa9a5a wp-block-paragraph\">L’evento riunisce sviluppatrici, designer, imprenditrici, specialiste del marketing digitale e leader del settore per condividere storie, esperienze, sfide e trovare nuove ispirazioni, nuovi obiettivi e nuove strade da percorrere. </p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>La tecnologia è ancora erroneamente ritenuta “non adatta” alle persone socializzate come donne</strong>: questa convinzione è spesso assai radicata nell’immaginario collettivo, anche in quello delle stesse donne. È una convinzione che è frutto dei retaggi culturali e dell’educazione che abbiamo ricevuto e che ha spesso indirizzato le donne verso altre professioni.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Vogliamo cogliere l’occasione della Giornata internazionale dei diritti delle donne per</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>celebrare la diversità e contribuire a rendere la nostra community più ampia e aperta;</li>\n\n\n\n<li>incoraggiare e rafforzare la fiducia necessaria per assumere ruoli di leadership, sia all&#8217;interno della Community di WordPress ma anche nel nostro quotidiano;</li>\n\n\n\n<li>ispirare le donne nel mondo della tecnologia attraverso le storie, le esperienze e la leadership di altre donne professioniste.</li>\n</ul>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-dots\" />\n\n\n\n<h2 class=\"wp-block-heading has-text-align-center has-ast-global-color-2-color has-text-color\">Scopri il programma</h2>\n\n\n\n<p class=\"has-text-align-center wp-container-content-9cfa9a5a wp-block-paragraph\">Unisciti a noi l’11 marzo 2025 e partecipa:</p>\n\n\n\n<p class=\"has-text-align-center wp-container-content-9cfa9a5a wp-block-paragraph\"><strong>in presenza:</strong> dalle 16:00 alle 18:00, presso la <a href=\"https://maps.app.goo.gl/8zxadcbbD4PmStzc6\" data-type=\"link\" data-id=\"https://maps.app.goo.gl/8zxadcbbD4PmStzc6\">Casa delle Donne &#8211; Via Aminale 20/22 &#8211; Terni</a></p>\n\n\n\n<p class=\"has-text-align-center wp-container-content-9cfa9a5a wp-block-paragraph\"><strong>online: dalle 18:00</strong> puoi partecipare alla diretta iscrivendoti tramite la pagina meetup.com di <a href=\"https://www.meetup.com/it-IT/wordpress-meetup-terni/events/306394447/\">Terni</a> e <a href=\"https://www.meetup.com/it-IT/meetup-wordpress-ancona/events/306515237/\">Ancona</a></p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-group alignfull is-layout-flow wp-block-group-is-layout-flow\">\n<figure class=\"wp-block-table alignwide is-style-stripes\"><table class=\"has-blueberry-3-background-color has-background has-fixed-layout\"><thead><tr><th><strong>PROGRAMMA</strong></th><th>Topic</th><th>descrizione</th><th>Speaker</th></tr></thead><tbody><tr><td><strong>16:30 &#8211; 18:00</strong></td><td><strong>Tavola Rotonda</strong> &#8211; solo in presenza</td><td> <strong>&#8220;Sostenere e sostenerci: strategie per una maggiore rappresentanza femminile nel mondo digitale&#8221;</strong></td><td>Margherita Pelonara (<a href=\'https://profiles.wordpress.org/margheweb/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>margheweb</a>) e Eleonora Anzini (<a href=\'https://profiles.wordpress.org/eleonoraanzini/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>eleonoraanzini</a>) per la Community WordPress Italia, Irene Loesch e Simona Schiavoni per la Casa delle Donne di Terni</td></tr><tr><td><strong>18:00 &#8211; 20:00</strong></td><td><strong>Speciale WordPress Meetup Terni</strong><br>(in presenza presso la Casa delle Donne e ONLINE)</td><td><strong>&#8220;Ricominciare a 50 anni: l’opportunità del mondo tech&#8221;</strong></td><td>Laura Sacco (<a href=\'https://profiles.wordpress.org/lasacco/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>lasacco</a>)</td></tr><tr><td></td><td></td><td><strong>&#8220;Siti WordPress per il bene comune: strumenti e strategie&#8221;</strong></td><td>Gloria Liuni (<a href=\'https://profiles.wordpress.org/glorialchemica/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>glorialchemica</a>)</td></tr><tr><td></td><td></td><td><strong>&#8220;Empowerment femminile: il ruolo del mentoring&#8221;</strong></td><td>Simona Simionato (<a href=\'https://profiles.wordpress.org/simo70/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>simo70</a>)</td></tr><tr><td></td><td></td><td><strong>&#8220;Aude Et Effice&#8221; &#8211; Grace Murray Hopper. Storie di informatica al femminile&#8221;</strong></td><td>Lidia Pellizzaro (<a href=\'https://profiles.wordpress.org/lidialab/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>lidialab</a>)</td></tr><tr><td></td><td></td><td><strong>&#8220;Dal dubbio alla crescita: il valore di riconoscersi nella leadership femminile&#8221;&nbsp;</strong></td><td>Isotta Peira (<a href=\'https://profiles.wordpress.org/peiraisotta/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>peiraisotta</a>)</td></tr></tbody></table></figure>\n\n\n\n<div style=\"height:4rem\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n</div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size wp-container-content-9cfa9a5a wp-block-paragraph\"><strong>PER RICEVERE IL LINK</strong> <strong>PER PARTECIPARE ALLA DIRETTA</strong><br>iscriviti tramite le pagina meetup.com di <a href=\"https://www.meetup.com/it-IT/wordpress-meetup-terni/events/306394447/\">Terni</a>, <a href=\"https://www.meetup.com/it-IT/meetup-wordpress-ancona/events/306515237/\">Ancona</a> oppure in quella del tuo WordPress Meetup se ha aderito all&#8217;iniziativa.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"4097\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:97:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tutti i meetup di dicembre 2024\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://it.wordpress.org/news/2024/12/tutti-i-meetup-di-dicembre-2024/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://it.wordpress.org/news/2024/12/tutti-i-meetup-di-dicembre-2024/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 10 Dec 2024 15:11:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:9:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:7:\"catania\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:6:\"genova\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:6:\"milano\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:4:\"pisa\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:5;a:5:{s:4:\"data\";s:13:\"reggio emilia\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:6;a:5:{s:4:\"data\";s:4:\"roma\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:7;a:5:{s:4:\"data\";s:7:\"treviso\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:8;a:5:{s:4:\"data\";s:6:\"verona\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://it.wordpress.org/?p=4082\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:353:\"In tutta Italia ci sono meetup WordPress! I meetup sono incontri gratuiti e aperti a tutti, in cui le community locali si incontrano per condividere conoscenze, conoscersi e fare rete. Se non sai cos’è un meetup leggi qui. Tutti i meetup WordPress italiani attivi sono elencati qui. Nei prossimi giorni, in ordine cronologico, si incontrano [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Margherita Pelonara\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3530:\"<p class=\"wp-block-paragraph\">In tutta Italia ci sono meetup WordPress!</p><p>I meetup sono <strong>incontri gratuiti e aperti a tutti,</strong> in cui le community locali si incontrano per condividere conoscenze, conoscersi e fare rete.</p><p class=\"wp-block-paragraph\">Se non sai cos’è un meetup <a href=\"https://it.wordpress.org/meetup/guida-ai-meetup-di-wordpress/\">leggi qui.</a></p><p class=\"wp-block-paragraph\">Tutti i meetup WordPress italiani attivi sono <a href=\"https://it.wordpress.org/meetup/\">elencati qui.</a></p><p class=\"wp-block-paragraph\"><strong>Nei prossimi giorni, <em>in ordine cronologico</em>, si incontrano le community di:</strong></p><h2 class=\"wp-block-heading\">Milano</h2><p class=\"wp-block-paragraph\">mer 11 dic, ore 19:00, &#8220;Sessione aperta domande e risposte&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-milano/events/304709729\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p><h2 class=\"wp-block-heading\">Reggio Emilia</h2><p class=\"wp-block-paragraph\">gio 12 dic, ore 18:30, &#8220;Reggio Emilia WP MeetUp La cassetta degli attrezzi del marketer&#8221; &#8211; <a href=\"https://www.meetup.com/reggio-emilia-wordpress-meetup/events/304914111\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p><h2 class=\"wp-block-heading\">Treviso</h2><p class=\"wp-block-paragraph\">gio 12 dic, ore 19:30, &#8220;Pizza di fine anno Treviso WordPress Meetup&#8221; &#8211; <a href=\"https://www.meetup.com/treviso-wordpress-meetup/events/304999905\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p><h2 class=\"wp-block-heading\">Roma</h2><p class=\"wp-block-paragraph\">ven 13 dic, ore 18:30, &#8220;Ask me anything about WordPress + cena di Natale&#8221; &#8211; <a href=\"https://www.meetup.com/romawordpress/events/304882472\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p><h2 class=\"wp-block-heading\">Genova</h2><p class=\"wp-block-paragraph\">lun 16 dic, ore 20:00, &#8220;Cena di fine anno in pizzeria!&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-genova/events/304894658\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p><h2 class=\"wp-block-heading\">Verona</h2><p class=\"wp-block-paragraph\">mar 17 dic, ore 19:00, &#8220;WordPress Meetup Verona #70 Strumentie risorse che facilitano il lavoro&#8221; &#8211; <a href=\"https://www.meetup.com/verona-wordpress-meetup/events/305005294\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p><h2 class=\"wp-block-heading\">Pisa</h2><p class=\"wp-block-paragraph\">mer 18 dic, ore 18:00, &#8220;WordPress go live: Il Tuo Sito Ovunque in Pochi Minuti&#8221; &#8211; <a href=\"https://www.meetup.com/pisa-wordpress-meetup/events/305012538\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p><h2 class=\"wp-block-heading\">Catania</h2><p class=\"wp-block-paragraph\">gio 19 dic, ore 19:00, &#8220;WordPress Meetup Catania Dicembre 2024: Performance&#8221; &#8211; <a href=\"https://www.meetup.com/meetup-wordpress-catania/events/304842161\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p><div style=\"height:var(--wp--preset--spacing--50)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><p class=\"has-text-align-center has-dark-blueberry-color has-blueberry-3-background-color has-text-color has-background has-link-color has-extra-large-font-size wp-block-paragraph\">… articolo in aggiornamento…</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"https://it.wordpress.org/news/2024/12/tutti-i-meetup-di-dicembre-2024/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"4082\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:103:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n		\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tutti i meetup di novembre 2024\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://it.wordpress.org/news/2024/11/tutti-i-meetup-di-novembre-2024/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://it.wordpress.org/news/2024/11/tutti-i-meetup-di-novembre-2024/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 13 Nov 2024 09:56:54 +0000\";s:7:\"at