_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Matteo Enna\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4253:\"\n<p class=\"wp-block-paragraph\"><p>In tutta Italia ci sono meetup WordPress!</p><p>I meetup sono <strong>incontri gratuiti e aperti a tutti,</strong> in cui le community locali si incontrano per condividere conoscenze, conoscersi e fare rete.</p></p>\n\n\n\n<p class=\"wp-block-paragraph\">Se non sai cos’è un meetup <a href=\"https://it.wordpress.org/meetup/guida-ai-meetup-di-wordpress/\">leggi qui.</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">Tutti i meetup WordPress italiani attivi sono <a href=\"https://it.wordpress.org/meetup/\">elencati qui.</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nei prossimi giorni, <em>in ordine cronologico</em>, si incontrano le community di:</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Milano</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mer 11 set, ore 19:00, &#8220;Impact of AI technologies on WordPress: a survey&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-milano/events/302193433\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Pisa</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mer 18 set, ore 18:00, &#8220;Esploriamo Insieme i nuovi percorsi formativi su learn.wordpress.org&#8221; &#8211; <a href=\"https://www.meetup.com/pisa-wordpress-meetup/events/303112446\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Genova</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mer 18 set, ore 18:30, &#8220;WP4ME : Niccolò Bellicchi&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-genova/events/303092132\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cagliari</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mer 18 set, ore 19:00, &#8220;Prepararsi al do_action di Ottobre: Costruire il Futuro Digitale con WordPress&#8221; &#8211; <a href=\"https://www.meetup.com/cagliari-wordpress-meetup/events/303217240\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Napoli</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mer 18 set, ore 19:00, &#8221; Buoni Propositi&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-napoli-meetup/events/302573336\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Brescia</h2>\n\n\n\n<p class=\"wp-block-paragraph\">gio 19 set, ore 18:30, &#8220;Quali soluzioni scegliere per creare un sito con WordPress&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-brescia/events/302571388\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Reggio Emilia</h2>\n\n\n\n<p class=\"wp-block-paragraph\">gio 19 set, ore 18:30, &#8220;Reggio Emilia WordPress MeetUp Si riparte! &#8221; &#8211; <a href=\"https://www.meetup.com/reggio-emilia-wordpress-meetup/events/302385477\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Ancona</h2>\n\n\n\n<p class=\"wp-block-paragraph\">gio 19 set, ore 19:00, &#8220;Meet &amp; Greet &#8211; Ricominciamo?&#8221; &#8211; <a href=\"https://www.meetup.com/meetup-wordpress-ancona/events/302514836\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Vicenza</h2>\n\n\n\n<p class=\"wp-block-paragraph\">mar 24 set, ore 19:00, &#8220;Incontro del meetup dopo la pausa estiva&#8221; &#8211; <a href=\"https://www.meetup.com/wordpress-meetup-vicenza/events/302666307\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Catania</h2>\n\n\n\n<p class=\"wp-block-paragraph\">gio 26 set, ore 19:00, &#8220;WP Meetup Catania Settembre &#8217;24&#8221; &#8211; <a href=\"https://www.meetup.com/meetup-wordpress-catania/events/302529229\" target=\"_blank\" rel=\"noreferrer noopener\">iscriviti qui per partecipare</a></p>\n\n\n\n<div style=\"height:var(--wp--preset--spacing--50)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-dark-blueberry-color has-blueberry-3-background-color has-text-color has-background has-link-color has-extra-large-font-size wp-block-paragraph\">… articolo in aggiornamento…</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://it.wordpress.org/news/2024/09/tutti-i-meetup-di-settembre-2024/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3947\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:35:\"https://it.wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_expl